1. export {};
2. 
3. type Metric = "euclidean" | "manhattan" | "chebyshev" | "minkowski3" | "minkowski05";
4. 
5. interface Site {
6.   id: string;
7.   x: number;
8.   y: number;
9.   metric: Metric;
10.   r: number;
11.   g: number;
12.   b: number;
13. }
14. 
15. const METRIC_LABEL: Record<Metric, string> = {
16.   euclidean: "L2",
17.   manhattan: "L1",
18.   chebyshev: "L∞",
19.   minkowski3: "L3",
20.   minkowski05: "L½",
21. };
22. 
23. const METRIC_FORMULA: Record<Metric, string> = {
24.   euclidean: "sqrt(dx² + dy²)",
25.   manhattan: "dx + dy",
26.   chebyshev: "max(dx, dy)",
27.   minkowski3: "(dx³ + dy³)^(1/3)",
28.   minkowski05: "(sqrt(dx) + sqrt(dy))²",
29. };
30. 
31. const METRIC_GENERIC_CALC: Record<Metric, string> = {
32.   euclidean: "sqrt(x² + y²)",
33.   manhattan: "x + y",
34.   chebyshev: "max(x, y)",
35.   minkowski3: "(x³ + y³)^(1/3)",
36.   minkowski05: "(sqrt(x) + sqrt(y))²",
37. };
38. 
39. const METRIC_INDEX: Record<Metric, number> = {
40.   euclidean: 0,
41.   manhattan: 1,
42.   chebyshev: 2,
43.   minkowski3: 3,
44.   minkowski05: 4,
45. };
46. 
47. const VERT = `#version 300 es
48. in vec2 a_pos;
49. void main() { gl_Position = vec4(a_pos, 0.0, 1.0); }
50. `;
51. 
52. const FRAG = `#version 300 es
53. precision highp float;
54. 
55. const int MAX = 64;
56. 
57. uniform vec2  u_res;
58. uniform float u_dpr;
59. uniform int   u_n;
60. uniform vec2  u_sites[MAX];
61. uniform vec3  u_colors[MAX];
62. uniform int   u_metrics[MAX];
63. 
64. out vec4 fragColor;
65. 
66. float vdist(int m, float ax, float ay) {
67.   if (m == 0) return sqrt(ax*ax + ay*ay);
68.   if (m == 1) return ax + ay;
69.   if (m == 2) return max(ax, ay);
70.   if (m == 3) return pow(ax*ax*ax + ay*ay*ay, 1.0/3.0);
71.   float s = sqrt(ax) + sqrt(ay); return s*s;
72. }
73. 
74. vec2 vdist_grad(int m, vec2 dp) {
75.   float ax = abs(dp.x), ay = abs(dp.y);
76.   float sx = sign(dp.x), sy = sign(dp.y);
77.   if (m == 0) {
78.     float d = sqrt(ax*ax + ay*ay);
79.     return d < 1e-7 ? vec2(0.0) : dp / d;
80.   }
81.   if (m == 1) return vec2(sx, sy);
82.   if (m == 2) {
83.     if (ax > ay) return vec2(sx, 0.0);
84.     if (ay > ax) return vec2(0.0, sy);
85.     return vec2(sx, sy) * 0.5;
86.   }
87.   if (m == 3) {
88.     float d3 = ax*ax*ax + ay*ay*ay;
89.     float d  = pow(d3, 1.0/3.0);
90.     return d < 1e-7 ? vec2(0.0) : vec2(sx*ax*ax, sy*ay*ay) / (d*d);
91.   }
92.   float sax = sqrt(max(ax, 1e-7)), say = sqrt(max(ay, 1e-7));
93.   float sum = sqrt(ax) + sqrt(ay);
94.   return vec2(ax < 1e-7 ? 0.0 : sx * sum / sax,
95.               ay < 1e-7 ? 0.0 : sy * sum / say);
96. }
97. 
98. void main() {
99.   if (u_n == 0) { fragColor = vec4(0.0); return; }
100. 
101.   vec2 p = vec2(gl_FragCoord.x, u_res.y - gl_FragCoord.y);
102. 
103.   float d1 = 1e9, d2 = 1e9;
104.   int owner = 0, owner2 = 0;
105. 
106.   for (int i = 0; i < MAX; i++) {
107.     if (i >= u_n) break;
108.     float d = vdist(u_metrics[i], abs(p.x - u_sites[i].x), abs(p.y - u_sites[i].y));
109.     if (d < d1) { d2 = d1; owner2 = owner; d1 = d; owner = i; }
110.     else if (d < d2) { d2 = d; owner2 = i; }
111.   }
112. 
113.   float gap = d2 - d1;
114.   vec2 g1 = vdist_grad(u_metrics[owner],  p - u_sites[owner]);
115.   vec2 g2 = vdist_grad(u_metrics[owner2], p - u_sites[owner2]);
116.   float grad = max(length(g2 - g1), 1e-4);
117.   float borderDist = gap / grad;
118.   float border = smoothstep(0.0, 1.5 * u_dpr, borderDist);
119.   fragColor = vec4(u_colors[owner] * mix(0.22, 1.0, border), 1.0);
120. }
121. `;
122. 
123. const glCanvas = document.querySelector<HTMLCanvasElement>("#voronoi-gl");
124. const markerCanvas = document.querySelector<HTMLCanvasElement>("#voronoi-markers");
125. const stage = document.querySelector<HTMLDivElement>("#voronoi-stage");
126. const clearButton = document.querySelector<HTMLButtonElement>("#voronoi-clear");
127. const help = document.querySelector<HTMLElement>("#voronoi-help");
128. const coords = document.querySelector<HTMLElement>("#voronoi-coords");
129. const distances = document.querySelector<HTMLElement>("#voronoi-distances");
130. const empty = document.querySelector<HTMLElement>("#voronoi-empty");
131. const metricButtons = Array.from(document.querySelectorAll<HTMLButtonElement>(".metric-button"));
132. 
133. if (glCanvas && markerCanvas && stage && clearButton && help && coords && distances && empty) {
134.   const gl = glCanvas.getContext("webgl2", { alpha: true, premultipliedAlpha: false });
135.   const markerCtx = markerCanvas.getContext("2d");
136. 
137.   if (gl && markerCtx) {
138.     let nextId = 0;
139.     let siteCount = 0;
140.     let sites: Site[] = [];
141.     let selectedId: string | null = null;
142.     let currentMetric: Metric = "euclidean";
143.     let mousePos: { x: number; y: number } | null = null;
144.     let drag: {
145.       id: string;
146.       startMouseX: number;
147.       startMouseY: number;
148.       origX: number;
149.       origY: number;
150.       moved: boolean;
151.     } | null = null;
152.     let mouseDownOnSite = false;
153. 
154.     const prog = gl.createProgram();
155.     if (!prog) throw new Error("Unable to create WebGL program");
156. 
157.     gl.attachShader(prog, compileShader(gl, gl.VERTEX_SHADER, VERT));
158.     gl.attachShader(prog, compileShader(gl, gl.FRAGMENT_SHADER, FRAG));
159.     gl.linkProgram(prog);
160.     gl.useProgram(prog);
161. 
162.     const buf = gl.createBuffer();
163.     gl.bindBuffer(gl.ARRAY_BUFFER, buf);
164.     gl.bufferData(gl.ARRAY_BUFFER, new Float32Array([
165.       -1, -1, 1, -1, -1, 1,
166.       -1, 1, 1, -1, 1, 1,
167.     ]), gl.STATIC_DRAW);
168. 
169.     const loc = gl.getAttribLocation(prog, "a_pos");
170.     gl.enableVertexAttribArray(loc);
171.     gl.vertexAttribPointer(loc, 2, gl.FLOAT, false, 0, 0);
172. 
173.     const uniforms = {
174.       res: gl.getUniformLocation(prog, "u_res"),
175.       dpr: gl.getUniformLocation(prog, "u_dpr"),
176.       n: gl.getUniformLocation(prog, "u_n"),
177.       sites: gl.getUniformLocation(prog, "u_sites"),
178.       colors: gl.getUniformLocation(prog, "u_colors"),
179.       metrics: gl.getUniformLocation(prog, "u_metrics"),
180.     };
181. 
182.     function compileShader(glContext: WebGL2RenderingContext, type: number, src: string) {
183.       const shader = glContext.createShader(type);
184.       if (!shader) throw new Error("Unable to create WebGL shader");
185.       glContext.shaderSource(shader, src);
186.       glContext.compileShader(shader);
187.       return shader;
188.     }
189. 
190.     function metricDist(m: Metric, ax: number, ay: number): number {
191.       switch (m) {
192.         case "euclidean": return Math.sqrt(ax * ax + ay * ay);
193.         case "manhattan": return ax + ay;
194.         case "chebyshev": return Math.max(ax, ay);
195.         case "minkowski3": return Math.cbrt(ax * ax * ax + ay * ay * ay);
196.         case "minkowski05": {
197.           const s = Math.sqrt(ax) + Math.sqrt(ay);
198.           return s * s;
199.         }
200.       }
201.     }
202. 
203.     function fmt(n: number): string {
204.       return Math.abs(n - Math.round(n)) < 0.05 ? String(Math.round(n)) : n.toFixed(1);
205.     }
206. 
207.     function metricCalculation(m: Metric, dx: number, dy: number): string {
208.       const d = metricDist(m, dx, dy);
209.       const x = fmt(dx);
210.       const y = fmt(dy);
211.       const v = fmt(d);
212.       switch (m) {
213.         case "euclidean": return `sqrt(${x}² + ${y}²) = ${v}`;
214.         case "manhattan": return `${x} + ${y} = ${v}`;
215.         case "chebyshev": return `max(${x}, ${y}) = ${v}`;
216.         case "minkowski3": return `(${x}³ + ${y}³)^(1/3) = ${v}`;
217.         case "minkowski05": return `(sqrt(${x}) + sqrt(${y}))² = ${v}`;
218.       }
219.     }
220. 
221.     function hslToRgb(h: number, s: number, l: number): [number, number, number] {
222.       s /= 100;
223.       l /= 100;
224.       const k = (n: number) => (n + h / 30) % 12;
225.       const a = s * Math.min(l, 1 - l);
226.       const f = (n: number) => l - a * Math.max(-1, Math.min(k(n) - 3, Math.min(9 - k(n), 1)));
227.       return [Math.round(f(0) * 255), Math.round(f(8) * 255), Math.round(f(4) * 255)];
228.     }
229. 
230.     function renderGL() {
231.       const dpr = window.devicePixelRatio || 1;
232. 
233.       gl.viewport(0, 0, glCanvas.width, glCanvas.height);
234.       gl.uniform2f(uniforms.res, glCanvas.width, glCanvas.height);
235.       gl.uniform1f(uniforms.dpr, dpr);
236.       gl.uniform1i(uniforms.n, sites.length);
237. 
238.       if (sites.length > 0) {
239.         const sv = new Float32Array(sites.length * 2);
240.         const cv = new Float32Array(sites.length * 3);
241.         const mv = new Int32Array(sites.length);
242.         for (let i = 0; i < sites.length; i++) {
243.           sv[i * 2] = sites[i].x * dpr;
244.           sv[i * 2 + 1] = sites[i].y * dpr;
245.           cv[i * 3] = sites[i].r / 255;
246.           cv[i * 3 + 1] = sites[i].g / 255;
247.           cv[i * 3 + 2] = sites[i].b / 255;
248.           mv[i] = METRIC_INDEX[sites[i].metric];
249.         }
250.         gl.uniform2fv(uniforms.sites, sv);
251.         gl.uniform3fv(uniforms.colors, cv);
252.         gl.uniform1iv(uniforms.metrics, mv);
253.       }
254. 
255.       gl.drawArrays(gl.TRIANGLES, 0, 6);
256.     }
257. 
258.     function renderMarkers() {
259.       const dpr = window.devicePixelRatio || 1;
260. 
261.       markerCtx.clearRect(0, 0, markerCanvas.width, markerCanvas.height);
262.       markerCtx.save();
263.       markerCtx.scale(dpr, dpr);
264. 
265.       for (const site of sites) {
266.         if (site.id === selectedId) {
267.           markerCtx.beginPath();
268.           markerCtx.arc(site.x, site.y, 11, 0, Math.PI * 2);
269.           markerCtx.strokeStyle = "#fff";
270.           markerCtx.lineWidth = 2.5;
271.           markerCtx.stroke();
272.           markerCtx.beginPath();
273.           markerCtx.arc(site.x, site.y, 11, 0, Math.PI * 2);
274.           markerCtx.strokeStyle = "rgba(0,0,0,0.4)";
275.           markerCtx.lineWidth = 1;
276.           markerCtx.stroke();
277.         }
278. 
279.         markerCtx.beginPath();
280.         markerCtx.arc(site.x, site.y, 6, 0, Math.PI * 2);
281.         markerCtx.fillStyle = "rgba(0,0,0,0.45)";
282.         markerCtx.fill();
283. 
284.         markerCtx.beginPath();
285.         markerCtx.arc(site.x, site.y, 4, 0, Math.PI * 2);
286.         markerCtx.fillStyle = "#fff";
287.         markerCtx.fill();
288. 
289.         markerCtx.font = "bold 11px ui-monospace, monospace";
290.         markerCtx.fillStyle = "rgba(0,0,0,0.7)";
291.         markerCtx.fillText(METRIC_LABEL[site.metric], site.x + 9, site.y + 4);
292.       }
293. 
294.       markerCtx.restore();
295.     }
296. 
297.     function render() {
298.       renderGL();
299.       renderMarkers();
300.       renderControls();
301.       renderHover();
302.       empty.style.display = sites.length === 0 ? "flex" : "none";
303.     }
304. 
305.     function resizeCanvases() {
306.       const dpr = window.devicePixelRatio || 1;
307.       const w = stage.clientWidth;
308.       const h = stage.clientHeight;
309. 
310.       for (const canvas of [glCanvas, markerCanvas]) {
311.         canvas.width = w * dpr;
312.         canvas.height = h * dpr;
313.         canvas.style.width = `${w}px`;
314.         canvas.style.height = `${h}px`;
315.       }
316. 
317.       render();
318.     }
319. 
320.     function getPos(e: MouseEvent) {
321.       const rect = glCanvas.getBoundingClientRect();
322.       return {
323.         x: e.clientX - rect.left,
324.         y: e.clientY - rect.top,
325.       };
326.     }
327. 
328.     function findNear(x: number, y: number, r = 14): Site | null {
329.       let best: Site | null = null;
330.       let bestD = r;
331.       for (const site of sites) {
332.         const d = Math.hypot(site.x - x, site.y - y);
333.         if (d < bestD) {
334.           bestD = d;
335.           best = site;
336.         }
337.       }
338.       return best;
339.     }
340. 
341.     function activeMetric() {
342.       if (!selectedId) return currentMetric;
343.       return sites.find((site) => site.id === selectedId)?.metric ?? currentMetric;
344.     }
345. 
346.     function renderControls() {
347.       const active = activeMetric();
348.       for (const button of metricButtons) {
349.         button.classList.toggle("is-active", button.dataset.metric === active);
350.       }
351.       help.textContent = selectedId ? "drag · change metric · right-click removes" : "click to place · right-click removes";
352.     }
353. 
354.     function renderHover() {
355.       coords.style.visibility = mousePos ? "visible" : "hidden";
356.       coords.textContent = mousePos ? `(${Math.round(mousePos.x)}, ${Math.round(mousePos.y)})` : "(0, 0)";
357.       distances.replaceChildren();
358. 
359.       if (sites.length === 0) return;
360. 
361.       const hover = mousePos
362.         ? sites.map((site) => ({
363.           site,
364.           d: metricDist(site.metric, Math.abs(mousePos!.x - site.x), Math.abs(mousePos!.y - site.y)),
365.         }))
366.         : null;
367.       const hoverMin = hover ? Math.min(...hover.map((item) => item.d)) : Infinity;
368.       const entries = hover ?? sites.map((site) => ({ site, d: null as number | null }));
369. 
370.       for (const { site, d } of entries) {
371.         const winner = d !== null && d === hoverMin;
372.         const content = mousePos
373.           ? metricCalculation(site.metric, Math.abs(mousePos.x - site.x), Math.abs(mousePos.y - site.y))
374.           : METRIC_GENERIC_CALC[site.metric];
375. 
376.         const entry = document.createElement("span");
377.         entry.className = `distance-entry${winner ? " is-winner" : ""}`;
378.         entry.title = mousePos
379.           ? `dx=${fmt(Math.abs(mousePos.x - site.x))}, dy=${fmt(Math.abs(mousePos.y - site.y))}; ${METRIC_LABEL[site.metric]}: ${METRIC_FORMULA[site.metric]}`
380.           : `${METRIC_LABEL[site.metric]}: ${METRIC_FORMULA[site.metric]}`;
381. 
382.         const dot = document.createElement("span");
383.         dot.className = "distance-dot";
384.         dot.style.background = `rgb(${site.r}, ${site.g}, ${site.b})`;
385.         dot.style.boxShadow = winner ? "0 0 0 1.5px var(--fg)" : "none";
386. 
387.         const label = document.createElement("span");
388.         label.className = "distance-label";
389.         label.textContent = METRIC_LABEL[site.metric];
390. 
391.         const value = document.createElement("span");
392.         value.className = "distance-value";
393.         value.textContent = content;
394. 
395.         entry.append(dot, label, value);
396.         if (winner) {
397.           const marker = document.createElement("span");
398.           marker.textContent = "◀";
399.           marker.style.color = "var(--accent)";
400.           marker.style.flexShrink = "0";
401.           entry.append(marker);
402.         }
403. 
404.         distances.append(entry);
405.       }
406.     }
407. 
408.     function setSelected(id: string | null) {
409.       selectedId = id;
410.       renderControls();
411.       renderMarkers();
412.     }
413. 
414.     stage.addEventListener("mousedown", (e) => {
415.       if (e.button !== 0) return;
416.       const { x, y } = getPos(e);
417.       const near = findNear(x, y);
418. 
419.       if (near) {
420.         setSelected(near.id);
421.         drag = { id: near.id, startMouseX: x, startMouseY: y, origX: near.x, origY: near.y, moved: false };
422.         mouseDownOnSite = true;
423.       } else {
424.         setSelected(null);
425.         mouseDownOnSite = false;
426.         drag = null;
427.       }
428.     });
429. 
430.     stage.addEventListener("mousemove", (e) => {
431.       const { x, y } = getPos(e);
432.       mousePos = { x, y };
433. 
434.       if (!drag) {
435.         stage.style.cursor = findNear(x, y) ? "grab" : "crosshair";
436.         renderHover();
437.         return;
438.       }
439. 
440.       const dx = x - drag.startMouseX;
441.       const dy = y - drag.startMouseY;
442.       if (!drag.moved && (Math.abs(dx) > 3 || Math.abs(dy) > 3)) {
443.         drag.moved = true;
444.         stage.style.cursor = "grabbing";
445.       }
446.       if (!drag.moved) return;
447. 
448.       const nx = Math.max(0, Math.min(glCanvas.clientWidth, drag.origX + dx));
449.       const ny = Math.max(0, Math.min(glCanvas.clientHeight, drag.origY + dy));
450.       sites = sites.map((site) => site.id === drag?.id ? { ...site, x: nx, y: ny } : site);
451.       render();
452.     });
453. 
454.     stage.addEventListener("mouseup", (e) => {
455.       if (e.button !== 0) return;
456.       stage.style.cursor = "crosshair";
457. 
458.       if (drag) {
459.         drag = null;
460.         return;
461.       }
462. 
463.       if (!mouseDownOnSite) {
464.         const { x, y } = getPos(e);
465.         const hue = (siteCount * 137.508) % 360;
466.         const [r, g, b] = hslToRgb(hue, 60, 68);
467.         const id = String(nextId++);
468.         siteCount++;
469.         sites = [...sites, { id, x, y, metric: currentMetric, r, g, b }];
470.         setSelected(id);
471.         render();
472.       }
473.     });
474. 
475.     stage.addEventListener("mouseleave", () => {
476.       mousePos = null;
477.       renderHover();
478.     });
479. 
480.     stage.addEventListener("contextmenu", (e) => {
481.       e.preventDefault();
482.       const { x, y } = getPos(e);
483.       const near = findNear(x, y);
484.       if (!near) return;
485.       if (selectedId === near.id) selectedId = null;
486.       sites = sites.filter((site) => site.id !== near.id);
487.       render();
488.     });
489. 
490.     for (const button of metricButtons) {
491.       button.addEventListener("click", () => {
492.         const metric = button.dataset.metric as Metric | undefined;
493.         if (!metric) return;
494.         currentMetric = metric;
495.         if (selectedId) {
496.           sites = sites.map((site) => site.id === selectedId ? { ...site, metric } : site);
497.         }
498.         render();
499.       });
500.     }
501. 
502.     clearButton.addEventListener("click", () => {
503.       selectedId = null;
504.       siteCount = 0;
505.       sites = [];
506.       render();
507.     });
508. 
509.     resizeCanvases();
510.     const observer = new ResizeObserver(resizeCanvases);
511.     observer.observe(stage);
512.   }
513. }
