432.     removeFigureNear(e.clientX - rect.left, e.clientY - rect.top);
433.   });
434. 
435.   figureButtons.forEach((btn) => {
436.     btn.addEventListener("click", () => {
437.       selectedFigure = btn.dataset.figure as FigureType;
438.       updateFigureButtons();
439.     });
440.   });
441. 
442.   launchButton.addEventListener("click", () => {
443.     if (gameState === "placing") {
444.       launchBall();
445.     } else if (gameState === "won" || gameState === "lost") {
446.       resetBall();
447.     }
448.   });
449. 
450.   clearButton.addEventListener("click", clearAll);
451. 
452.   function resize() {
453.     const parent = canvas.parentElement;
454.     if (!parent) return;
455.     viewport = { width: parent.clientWidth, height: parent.clientHeight };
456. 
457.     render.options.width = viewport.width;
458.     render.options.height = viewport.height;
459.     const pr = getPixelRatio();
460.     render.canvas.width = viewport.width * pr;
461.     render.canvas.height = viewport.height * pr;
462.     render.canvas.style.width = `${viewport.width}px`;
463.     render.canvas.style.height = `${viewport.height}px`;
464.     Render.setPixelRatio(render, pr);
465. 
466.     if (walls.length > 0) {
467.       for (const wall of walls) {
468.         World.remove(world, wall);
469.       }
470.       walls = [];
471.     }
472.     createWalls();
473.   }
474. 
475.   const observer = new ResizeObserver(resize);
476.   if (canvas.parentElement) observer.observe(canvas.parentElement);
477. 
478.   updateFigureButtons();
479.   resize();
480.   updateStatus();
481.   Render.run(render);
482.   Runner.run(runner, engine);
483. }
