     mouseOnCanvas = false;
   });

   canvas.addEventListener("click", (e) => {
     const rect = canvas.getBoundingClientRect();
     placeFigure(e.clientX - rect.left, e.clientY - rect.top);
   });

   canvas.addEventListener("contextmenu", (e) => {
     e.preventDefault();
     const rect = canvas.getBoundingClientRect();
