      if (site.id === selectedId) {
        markerCtx.beginPath();
        markerCtx.arc(site.x, site.y, 11, 0, Math.PI * 2);
        markerCtx.strokeStyle = "#fff";
        markerCtx.lineWidth = 2.5;
        markerCtx.stroke();
        markerCtx.beginPath();
        markerCtx.arc(site.x, site.y, 11, 0, Math.PI * 2);
        markerCtx.strokeStyle = "rgba(0,0,0,0.4)";
        markerCtx.lineWidth = 1;
        markerCtx.stroke();
      }

